// Extract sector and optional parameters from email body
const emailBody = $input.first().json.snippet || $input.first().json.textPlain || '';
const subject = $input.first().json.subject || '';
const senderEmail = $input.first().json.from?.value?.[0]?.address || $input.first().json.from || '';

// Parse sector from body - look for known patterns
const bodyLower = emailBody.toLowerCase().trim();

// Extract sector - support formats like:
// "NIFTY IT", "nifty bank", "Nifty Pharma", "IT", "Banking", etc.
let sector = 'NIFTY IT'; // default
let quarters = 4; // default
let specificCompanies = [];

// Sector mapping for Indian indices
const sectorMap = {
  'nifty it': { index: 'NIFTY IT', stocks: ['TCS', 'INFY', 'HCLTECH', 'WIPRO', 'TECHM', 'LTIM', 'PERSISTENT', 'COFORGE', 'MPHASIS', 'LTTS'] },
  'nifty bank': { index: 'NIFTY BANK', stocks: ['HDFCBANK', 'ICICIBANK', 'KOTAKBANK', 'AXISBANK', 'SBIN', 'INDUSINDBK', 'BANDHANBNK', 'FEDERALBNK', 'IDFCFIRSTB', 'PNB', 'BANKBARODA', 'AUBANK'] },
  'nifty pharma': { index: 'NIFTY PHARMA', stocks: ['SUNPHARMA', 'DRREDDY', 'CIPLA', 'DIVISLAB', 'APOLLOHOSP', 'LUPIN', 'TORNTPHARM', 'AUROPHARMA', 'BIOCON', 'ALKEM'] },
  'nifty auto': { index: 'NIFTY AUTO', stocks: ['M&M', 'TATAMOTORS', 'MARUTI', 'BAJAJ-AUTO', 'HEROMOTOCO', 'EICHERMOT', 'ASHOKLEY', 'BALKRISIND', 'BHARATFORG', 'BOSCHLTD', 'MRF', 'TVSMOTOR'] },
  'nifty fmcg': { index: 'NIFTY FMCG', stocks: ['HINDUNILVR', 'ITC', 'NESTLEIND', 'BRITANNIA', 'GODREJCP', 'DABUR', 'MARICO', 'COLPAL', 'TATACONSUM', 'VBL', 'UBL', 'EMAMILTD'] },
  'nifty metal': { index: 'NIFTY METAL', stocks: ['TATASTEEL', 'JSWSTEEL', 'HINDALCO', 'ADANIENT', 'VEDL', 'COALINDIA', 'NMDC', 'SAIL', 'NATIONALUM', 'JINDALSTEL'] },
  'nifty energy': { index: 'NIFTY ENERGY', stocks: ['RELIANCE', 'NTPC', 'POWERGRID', 'ONGC', 'BPCL', 'IOC', 'GAIL', 'ADANIGREEN', 'TATAPOWER', 'ADANIENSOL'] },
  'nifty realty': { index: 'NIFTY REALTY', stocks: ['DLF', 'GODREJPROP', 'OBEROIRLTY', 'PRESTIGE', 'PHOENIXLTD', 'BRIGADE', 'SOBHA', 'SUNTECK', 'MAHLIFE', 'LODHA'] },
  'nifty financial services': { index: 'NIFTY FIN SERVICE', stocks: ['HDFCBANK', 'ICICIBANK', 'BAJFINANCE', 'BAJAJFINSV', 'SBILIFE', 'HDFCLIFE', 'HDFCAMC', 'SBICARD', 'CHOLAFIN', 'MUTHOOTFIN'] },
  'it': { index: 'NIFTY IT', stocks: ['TCS', 'INFY', 'HCLTECH', 'WIPRO', 'TECHM', 'LTIM', 'PERSISTENT', 'COFORGE', 'MPHASIS', 'LTTS'] },
  'banking': { index: 'NIFTY BANK', stocks: ['HDFCBANK', 'ICICIBANK', 'KOTAKBANK', 'AXISBANK', 'SBIN', 'INDUSINDBK', 'BANDHANBNK', 'FEDERALBNK', 'IDFCFIRSTB', 'PNB', 'BANKBARODA', 'AUBANK'] },
  'pharma': { index: 'NIFTY PHARMA', stocks: ['SUNPHARMA', 'DRREDDY', 'CIPLA', 'DIVISLAB', 'APOLLOHOSP', 'LUPIN', 'TORNTPHARM', 'AUROPHARMA', 'BIOCON', 'ALKEM'] },
  'auto': { index: 'NIFTY AUTO', stocks: ['M&M', 'TATAMOTORS', 'MARUTI', 'BAJAJ-AUTO', 'HEROMOTOCO', 'EICHERMOT', 'ASHOKLEY', 'BALKRISIND', 'BHARATFORG', 'BOSCHLTD', 'MRF', 'TVSMOTOR'] },
  'fmcg': { index: 'NIFTY FMCG', stocks: ['HINDUNILVR', 'ITC', 'NESTLEIND', 'BRITANNIA', 'GODREJCP', 'DABUR', 'MARICO', 'COLPAL', 'TATACONSUM', 'VBL', 'UBL', 'EMAMILTD'] },
  'metal': { index: 'NIFTY METAL', stocks: ['TATASTEEL', 'JSWSTEEL', 'HINDALCO', 'ADANIENT', 'VEDL', 'COALINDIA', 'NMDC', 'SAIL', 'NATIONALUM', 'JINDALSTEL'] },
  'energy': { index: 'NIFTY ENERGY', stocks: ['RELIANCE', 'NTPC', 'POWERGRID', 'ONGC', 'BPCL', 'IOC', 'GAIL', 'ADANIGREEN', 'TATAPOWER', 'ADANIENSOL'] },
  'realty': { index: 'NIFTY REALTY', stocks: ['DLF', 'GODREJPROP', 'OBEROIRLTY', 'PRESTIGE', 'PHOENIXLTD', 'BRIGADE', 'SOBHA', 'SUNTECK', 'MAHLIFE', 'LODHA'] }
};

// Try to match sector from email body
for (const [key, value] of Object.entries(sectorMap)) {
  if (bodyLower.includes(key)) {
    sector = value.index;
    specificCompanies = value.stocks;
    break;
  }
}

// Extract quarters if mentioned (e.g., "last 6 quarters", "8 quarters")
const quarterMatch = bodyLower.match(/(\d+)\s*quarter/i);
if (quarterMatch) {
  quarters = parseInt(quarterMatch[1]);
}

return [{
  json: {
    sector,
    stocks: specificCompanies,
    quarters,
    senderEmail,
    originalBody: emailBody,
    timestamp: new Date().toISOString()
  }
}];

// Merge NSE live data with our static fallback
const parsed = $('Parse Email & Identify Sector').first().json;
let stocks = parsed.stocks || [];
let stockDetails = [];

// Try to use NSE API response
const nseData = $('Fetch NSE Index Constituents').first().json;
if (nseData && nseData.data && Array.isArray(nseData.data)) {
  stockDetails = nseData.data.map(s => ({
    symbol: s.symbol,
    company: s.meta?.companyName || s.symbol,
    lastPrice: s.lastPrice,
    change: s.change,
    pChange: s.pChange,
    marketCap: s.meta?.marketCap || null,
    industry: s.meta?.industry || parsed.sector
  }));
  stocks = stockDetails.map(s => s.symbol);
} else {
  // Fallback: use static list from parser
  stockDetails = stocks.map(s => ({
    symbol: s,
    company: s,
    lastPrice: null,
    change: null,
    pChange: null,
    marketCap: null,
    industry: parsed.sector
  }));
}

// Output each stock as a separate item for the loop
return stockDetails.map(stock => ({
  json: {
    ...stock,
    sector: parsed.sector,
    quarters: parsed.quarters,
    senderEmail: parsed.senderEmail,
    totalStocks: stocks.length
  }
}));

// Parse OpenAI response and extract structured data
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    let analysis;
    const content = item.json.message?.content || item.json.text || item.json.choices?.[0]?.message?.content || JSON.stringify(item.json);

    if (typeof content === 'string') {
      analysis = JSON.parse(content);
    } else {
      analysis = content;
    }

    results.push({ json: analysis });
  } catch (e) {
    results.push({
      json: {
        company: item.json.symbol || 'UNKNOWN',
        error: `Failed to parse: ${e.message}`,
        raw: item.json
      }
    });
  }
}

return results;

// Aggregate all company analyses and rank by confidence
const items = $input.all();
const senderEmail = $('Parse Email & Identify Sector').first().json.senderEmail;
const sector = $('Parse Email & Identify Sector').first().json.sector;
const quarters = $('Parse Email & Identify Sector').first().json.quarters;

// Filter out errors and sort by confidence score
const analyses = items
  .map(i => i.json)
  .filter(a => !a.error && a.confidenceClassification)
  .sort((a, b) => (b.confidenceClassification?.score || 0) - (a.confidenceClassification?.score || 0));

const errors = items.map(i => i.json).filter(a => a.error);

// Assign ranks
analyses.forEach((a, i) => {
  a.rank = i + 1;
});

// Build sector summary
const avgSentiment = analyses.reduce((sum, a) => sum + (a.sentimentScores?.composite_score || 0), 0) / (analyses.length || 1);
const avgCredibility = analyses.reduce((sum, a) => sum + (a.credibility?.score || 0), 0) / (analyses.length || 1);
const avgConfidence = analyses.reduce((sum, a) => sum + (a.confidenceClassification?.score || 0), 0) / (analyses.length || 1);

const tierCounts = {};
analyses.forEach(a => {
  const tier = a.confidenceClassification?.tier || 'UNKNOWN';
  tierCounts[tier] = (tierCounts[tier] || 0) + 1;
});

return [{
  json: {
    sector,
    quarters,
    senderEmail,
    totalCompanies: analyses.length,
    errorCount: errors.length,
    sectorSummary: {
      avgSentiment: Math.round(avgSentiment),
      avgCredibility: Math.round(avgCredibility),
      avgConfidence: Math.round(avgConfidence),
      tierDistribution: tierCounts
    },
    rankedCompanies: analyses,
    errors: errors.map(e => e.company),
    timestamp: new Date().toISOString()
  }
}];

