// Prepare final email response
const aggregated = $('Aggregate & Rank Companies').first().json;
const reportResponse = $('OpenAI Generate HTML Report').first().json;

let htmlReport = reportResponse.message?.content || reportResponse.text || reportResponse.choices?.[0]?.message?.content || '';

// Clean up markdown code fences if present
htmlReport = htmlReport.replace(/^```html\n?/i, '').replace(/\n?```$/i, '').trim();

// Build a quick summary for the email subject
const topCompanies = aggregated.rankedCompanies.slice(0, 3);
const topNames = topCompanies.map(c => `${c.companyName || c.company} (${c.confidenceClassification?.tier})`).join(', ');

// Build structured data attachment
const structuredData = {
  report: htmlReport,
  data: {
    stock_universe: aggregated.rankedCompanies.map(c => ({
      company: c.companyName || c.company,
      symbol: c.company,
      sector: c.sector,
      confidence_rank: c.rank
    })),
    sentiment_scores: aggregated.rankedCompanies.map(c => ({
      company: c.company,
      ...c.sentimentScores
    })),
    credibility_tracker: aggregated.rankedCompanies.map(c => ({
      company: c.company,
      ...c.credibility
    })),
    confidence_classification: aggregated.rankedCompanies.map(c => ({
      company: c.company,
      rank: c.rank,
      ...c.confidenceClassification,
      sentiment_score: c.sentimentScores?.composite_score,
      credibility_score: c.credibility?.score,
      summary: c.summary
    })),
    forward_triggers: aggregated.rankedCompanies.flatMap(c => 
      (c.forwardTriggers || []).map(t => ({ company: c.company, ...t }))
    )
  }
};

return [{
  json: {
    to: aggregated.senderEmail,
    subject: `[Earnings Sentiment] ${aggregated.sector} — Top: ${topNames}`,
    htmlReport,
    structuredData: JSON.stringify(structuredData),
    sector: aggregated.sector,
    totalCompanies: aggregated.totalCompanies,
    timestamp: aggregated.timestamp
  }
}];
